import org.w3c.dom.Document;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.xpath.XPath;
import javax.xml.xpath.XPathConstants;
import javax.xml.xpath.XPathExpressionException;
import javax.xml.xpath.XPathFactory;
import java.io.InputStream;

public class UserService {
    public String findUserRoleByUsername(String username) {
        try {
            // Load XML file from classpath
            InputStream xmlInput = getClass().getClassLoader().getResourceAsStream("users.xml");
            if (xmlInput == null) {
                return null;
            }

            // Create DOM document
            DocumentBuilderFactory dbFactory = DocumentBuilderFactory.newInstance();
            DocumentBuilder dBuilder = dbFactory.newDocumentBuilder();
            Document doc = dBuilder.parse(xmlInput);
            doc.getDocumentElement().normalize();

            // Create XPath instance and compile expression
            XPath xPath = XPathFactory.newInstance().newXPath();
            String expression = String.format("/users/user[name = '%s']/role/text()", username);
            String role = (String) xPath.evaluate(expression, doc, XPathConstants.STRING);

            // Return role or null if not found
            return role.isEmpty() ? null : role;
        } catch (Exception e) {
            // Handle any exceptions (parser errors, XPath errors, etc.)
            e.printStackTrace();
            return null;
        }
    }
}
